import{_ as a,o as t,c as o,ag as i}from"./chunks/framework.BZohXCq9.js";const h=JSON.parse('{"title":"Integración con Discord (Webhooks)","description":"","frontmatter":{},"headers":[],"relativePath":"maxstaff/discord.md","filePath":"maxstaff/discord.md"}'),s={name:"maxstaff/discord.md"};function l(n,e,r,d,c,u){return t(),o("div",null,[...e[0]||(e[0]=[i(`<h1 id="integracion-con-discord-webhooks" tabindex="-1">Integración con Discord (Webhooks) <a class="header-anchor" href="#integracion-con-discord-webhooks" aria-label="Permalink to &quot;Integración con Discord (Webhooks)&quot;">​</a></h1><blockquote><p>El plugin permite enviar notificaciones automáticas y registros detallados a un canal de tu servidor de Discord a través de Webhooks. Puedes registrar sanciones, alertas administrativas y reportes de jugadores en tiempo real.</p></blockquote><h2 id="_1-configuracion-basica" tabindex="-1">1. Configuración Básica <a class="header-anchor" href="#_1-configuracion-basica" aria-label="Permalink to &quot;1. Configuración Básica&quot;">​</a></h2><blockquote><p>Para activar esta función, debes configurar el archivo <code>discord.yml</code>.</p></blockquote><ol><li>Ve a tu servidor de Discord, haz clic derecho en el canal donde deseas recibir las alertas y selecciona <strong>Editar canal</strong>.</li><li>Dirígete a <strong>Integraciones</strong> &gt; <strong>Webhooks</strong> y crea un nuevo Webhook.</li><li>Copia la URL del Webhook y pégala en tu archivo <code>discord.yml</code>:</li></ol><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Reemplaza &quot;URL_AQUI&quot; con el enlace de tu Webhook</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">webhook-url</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;URL_AQUI&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">enabled</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Opciones de personalización global</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">global-image</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;[https://imgur.com/xLVotZb](https://imgur.com/xLVotZb)&quot;</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">server-name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Survival 1.20&quot;</span></span></code></pre></div><h2 id="_2-categorias-de-notificaciones" tabindex="-1">2. Categorías de Notificaciones <a class="header-anchor" href="#_2-categorias-de-notificaciones" aria-label="Permalink to &quot;2. Categorías de Notificaciones&quot;">​</a></h2><blockquote><p>El sistema está dividido en tres categorías principales. Puedes personalizar el color (en formato HEX), el autor y los campos de información para cada una.</p></blockquote><h3 id="sanciones" tabindex="-1">Sanciones <a class="header-anchor" href="#sanciones" aria-label="Permalink to &quot;Sanciones&quot;">​</a></h3><blockquote><p>Se envían automáticamente cuando un miembro del staff castiga a un jugador.</p></blockquote><ul><li><code>Ban:</code> Registra al usuario, el staff, la duración y la razón.</li><li><code>Mute:</code> Registra al usuario, el staff, la duración y la razón.</li><li><code>Kick:</code> Registra al usuario, el staff y la razón de la expulsión.</li><li><code>Warn:</code> Registra al usuario, el staff, la razón y la <strong>cantidad de advertencias acumuladas</strong>.</li></ul><h3 id="alertas-administrativas" tabindex="-1">Alertas Administrativas <a class="header-anchor" href="#alertas-administrativas" aria-label="Permalink to &quot;Alertas Administrativas&quot;">​</a></h3><blockquote><p>Notificaciones sobre acciones de moderación generales en el servidor.</p></blockquote><ul><li><code>Freeze / Unfreeze:</code> Avisa cuando un jugador es congelado o descongelado para revisión (SS).</li><li><code>Gestión de Chat:</code> Avisa cuando el chat global es limpiado (<code>chat_clear</code>), bloqueado (<code>chat_mute</code>) o desbloqueado (<code>chat_unmute</code>).</li><li><code>Staff Mode:</code> Registra cuando un miembro del equipo entra o sale del modo staff.</li></ul><h3 id="reportes" tabindex="-1">Reportes <a class="header-anchor" href="#reportes" aria-label="Permalink to &quot;Reportes&quot;">​</a></h3><blockquote><p>Avisa al instante cuando un jugador usa el comando de reportes.</p></blockquote><ul><li>Muestra quién reportó, a quién reportó, la razón y las <strong>coordenadas exactas</strong> (mundo, X, Y, Z) donde ocurrió el incidente.</li></ul><h2 id="_3-variables-disponibles" tabindex="-1">3. Variables Disponibles <a class="header-anchor" href="#_3-variables-disponibles" aria-label="Permalink to &quot;3. Variables Disponibles&quot;">​</a></h2><blockquote><p>Puedes usar estas variables dentro de la configuración de tus <em>embeds</em> en el <code>discord.yml</code> para mostrar información dinámica:</p></blockquote><table tabindex="0"><thead><tr><th style="text-align:left;">Variable</th><th style="text-align:left;">Descripción</th></tr></thead><tbody><tr><td style="text-align:left;"><code>{target}</code></td><td style="text-align:left;">Nombre del jugador afectado o reportado</td></tr><tr><td style="text-align:left;"><code>{staff}</code></td><td style="text-align:left;">Nombre del miembro del staff que ejecutó la acción</td></tr><tr><td style="text-align:left;"><code>{reason}</code></td><td style="text-align:left;">Razón de la sanción, alerta o reporte</td></tr><tr><td style="text-align:left;"><code>{duration}</code></td><td style="text-align:left;">Tiempo de la sanción (solo aplica para temporal bans/mutes)</td></tr><tr><td style="text-align:left;"><code>{count}</code></td><td style="text-align:left;">Número de advertencias (warns) acumuladas del jugador</td></tr><tr><td style="text-align:left;"><code>{reporter}</code></td><td style="text-align:left;">Nombre del jugador que emitió un reporte</td></tr><tr><td style="text-align:left;"><code>{face}</code></td><td style="text-align:left;">URL que muestra el avatar/cabeza 3D del jugador afectado</td></tr><tr><td style="text-align:left;"><code>{world}</code></td><td style="text-align:left;">Mundo donde se encontraba el jugador (usado en reportes)</td></tr><tr><td style="text-align:left;"><code>{x}</code>, <code>{y}</code>, <code>{z}</code></td><td style="text-align:left;">Coordenadas exactas del jugador (usado en reportes)</td></tr></tbody></table>`,20)])])}const g=a(s,[["render",l]]);export{h as __pageData,g as default};
